content:
Minimal fix: break reaper into bounded chunks, commit + release connection between each. Long tx dies → locks short → pool never starves. Add index so each chunk scans bounded rows, not 8M. No schedule change.

```sql
-- one-time migration: make reaper cheap per-chunk
CREATE INDEX CONCURRENTLY IF NOT EXISTS ix_sessions_expires_at
  ON sessions (expires_at)
  WHERE expires_at IS NOT NULL;
```

```java
// SessionReaper.java — replaces single-tx full-scan delete
public class SessionReaper {
    private static final int CHUNK_SIZE = 5_000;
    private static final Duration CHUNK_PAUSE = Duration.ofMillis(50);
    private static final Duration MAX_WALLCLOCK = Duration.ofMinutes(5);

    private final DataSource ds;   // dedicated pool, see config below
    private final Clock clock;

    public void reap() {
        Instant deadline = clock.instant().plus(MAX_WALLCLOCK);
        long totalDeleted = 0;
        while (clock.instant().isBefore(deadline)) {
            int deleted = deleteOneChunk();
            totalDeleted += deleted;
            if (deleted < CHUNK_SIZE) break;   // caught up
            sleepQuietly(CHUNK_PAUSE);         // yield to request traffic
        }
        log.info("reaper done: deleted={}", totalDeleted);
    }

    /** One short transaction. Connection is acquired, used, released. */
    private int deleteOneChunk() {
        try (Connection c = ds.getConnection()) {
            c.setAutoCommit(false);
            try (PreparedStatement ps = c.prepareStatement(
                    "DELETE FROM sessions " +
                    "WHERE id IN (" +
                    "  SELECT id FROM sessions " +
                    "  WHERE expires_at < now() " +
                    "  ORDER BY expires_at " +
                    "  LIMIT ? " +
                    "  FOR UPDATE SKIP LOCKED" +    // don't block checkout
                    ")")) {
                ps.setInt(1, CHUNK_SIZE);
                int n = ps.executeUpdate();
                c.commit();
                return n;
            } catch (SQLException e) {
                c.rollback();
                throw e;
            }
        } catch (SQLException e) {
            throw new RuntimeException(e);
        }
    }
}
```

```yaml
# application.yml — isolate scheduler from request path
spring:
  datasource:
    checkout:          # existing request pool
      maximum-pool-size: 20
      connection-timeout: 5000
    reaper:            # NEW: dedicated small pool for background work
      maximum-pool-size: 2
      connection-timeout: 2000
      leak-detection-threshold: 10000
```

Three things together: `FOR UPDATE SKIP LOCKED` means reaper never blocks checkout on the same row; 5k-row chunks keep each tx under ~50ms; dedicated 2-conn pool means even if reaper misbehaves it can't drain the 20 slots checkout needs.
